const benchmarkUrl = 'https://www.linkedin.com/posts/sabrina-compagno-6a410823_il-retail-multibrand-italiano-si-sta-reinventando-share-7457398029000806400-B4kD';

const parseInput = (value) => {
  if (!value) return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
};

const fixture = parseInput($env.TEST_POST_JSON);
const testPostUrl = String($env.TEST_POST_URL || (fixture && fixture.url) || benchmarkUrl);
const apifyOverride = parseInput($env.APIFY_TEST_INPUT_JSON);
const apifyInput = apifyOverride && typeof apifyOverride === 'object' && !Array.isArray(apifyOverride)
  ? apifyOverride
  : {
      startUrls: [{ url: testPostUrl }],
      urls: [testPostUrl],
      url: testPostUrl,
      postUrl: testPostUrl,
      scrapeComments: true,
      scrapeReactions: false,
      postNestedComments: true,
      postNestedReactions: false
    };

return [{
  json: {
    test_post_url: testPostUrl,
    expected: (fixture && fixture.expected) || null,
    apify_input: apifyInput,
    seen_at: new Date().toISOString()
  }
}];

const parseInput = (value) => {
  if (!value) return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
};

const fixture = parseInput($env.TEST_POST_JSON);
const expected = (fixture && fixture.expected) || null;
const testPostUrl = String($env.TEST_POST_URL || (fixture && fixture.url) || '');

const rows = [];
for (const item of items) {
  const value = item.json;
  if (Array.isArray(value)) rows.push(...value);
  else if (Array.isArray(value.items)) rows.push(...value.items);
  else if (Array.isArray(value.data)) rows.push(...value.data);
  else rows.push(value);
}

const pick = (obj, keys) => {
  for (const key of keys) {
    const value = obj && obj[key];
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return '';
};
const clean = (value) => String(value || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const hash = (input) => {
  let h = 2166136261;
  const text = String(input || '');
  for (let i = 0; i < text.length; i += 1) {
    h ^= text.charCodeAt(i);
    h += (h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24);
  }
  return (h >>> 0).toString(36);
};
const toAirtableDate = (value) => {
  if (value === null || value === undefined || value === '') return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value.toISOString();
  if (typeof value === 'number') {
    const date = new Date(value > 1e12 ? value : value * 1000);
    return Number.isNaN(date.getTime()) ? null : date.toISOString();
  }
  if (typeof value === 'string') {
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? value : parsed.toISOString();
  }
  if (typeof value === 'object') {
    const candidates = [value.iso, value.value, value.datetime, value.dateTime, value.publishedAt, value.published_at, value.time, value.timestamp, value.ts, value.date, value.createdAt, value.created_at];
    for (const candidate of candidates) {
      const converted = toAirtableDate(candidate);
      if (converted) return converted;
    }
    return null;
  }
  const parsed = new Date(String(value));
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
};
const makeAuthor = (source, fallbackName, fallbackUrl) => {
  const author = source || {};
  const name = clean(pick(author, ['name', 'fullName', 'author_name', 'authorName', 'userName', 'profileName']) || fallbackName);
  const url = String(pick(author, ['url', 'linkedinUrl', 'profileUrl', 'author_url', 'authorUrl', 'authorProfileUrl']) || fallbackUrl || '');
  const role = clean(pick(author, ['headline', 'role', 'title', 'authorRole', 'authorHeadline']) || '');
  return {
    canonical_id: String(url || name || `author:${hash(fallbackName || fallbackUrl || 'unknown')}`),
    name: name || 'Unknown author',
    url,
    role
  };
};
const makeComment = (comment, index, groupKey) => {
  const author = comment.author || comment.user || comment.profile || {};
  const authorName = clean(pick(author, ['name', 'fullName', 'author_name', 'authorName', 'userName', 'profileName']) || pick(comment, ['authorName', 'userName', 'name', 'author_name']) || 'Unknown author');
  const authorUrl = String(pick(author, ['url', 'linkedinUrl', 'profileUrl', 'author_url', 'authorUrl']) || pick(comment, ['authorUrl', 'profileUrl', 'author_url']) || '');
  const text = clean(pick(comment, ['text', 'commentText', 'content', 'body']));
  const canonicalId = String(pick(comment, ['canonical_id', 'id', 'urn']) || `comment:${index + 1}:${hash(`${groupKey}:${authorName}:${text}`)}`);
  return {
    canonical_id: canonicalId,
    author_name: authorName,
    author_url: authorUrl,
    author: makeAuthor(author, authorName, authorUrl),
    text
  };
};

const groups = new Map();
const ensureGroup = (key) => {
  if (!groups.has(key)) {
    groups.set(key, {
      canonical_id: key,
      url: '',
      text: '',
      published_at: null,
      author: { canonical_id: '', name: '', url: '', role: '' },
      comments: [],
      commentKeys: new Set(),
      rawSources: []
    });
  }
  return groups.get(key);
};
const addComment = (group, comment) => {
  if (!comment || !comment.text) return;
  const key = `${comment.canonical_id}|${comment.author_name}|${comment.text}`;
  if (group.commentKeys.has(key)) return;
  group.commentKeys.add(key);
  group.comments.push(comment);
};

for (const row of rows) {
  const postAuthor = row.author || row.user || row.profile || row.owner || {};
  const postUrl = String(pick(row, ['url', 'postUrl', 'link', 'linkedinUrl', 'postLink']) || '');
  const parentUrl = String(pick(row, ['parentUrl', 'parentPostUrl', 'parentPostURL']) || '');
  const text = clean(pick(row, ['text', 'postText', 'content', 'description', 'body', 'commentary']));
  const authorName = clean(pick(postAuthor, ['name', 'fullName', 'author_name', 'authorName', 'userName', 'profileName']) || pick(row, ['authorName', 'userName', 'profileName', 'author_name', 'name']));
  const authorUrl = String(pick(postAuthor, ['url', 'linkedinUrl', 'profileUrl', 'author_url', 'authorUrl', 'authorProfileUrl']) || pick(row, ['authorUrl', 'profileUrl', 'author_url']) || '');
  const authorRole = clean(pick(postAuthor, ['headline', 'role', 'title', 'authorRole', 'authorHeadline']) || pick(row, ['authorHeadline', 'authorRole', 'headline']));
  const canonicalId = String(pick(row, ['canonical_id', 'id', 'urn', 'activityId', 'postId']) || postUrl || parentUrl || `post:${hash(`${authorName}:${text}`)}`);
  const groupKey = parentUrl || postUrl || canonicalId;
  const group = ensureGroup(groupKey);

  if (!group.canonical_id || String(group.canonical_id).startsWith('post:')) group.canonical_id = canonicalId;
  if (!group.url) group.url = postUrl || parentUrl;
  if (text && (!group.text || text.length > group.text.length)) group.text = text;
  if (!group.published_at) group.published_at = toAirtableDate(pick(row, ['publishedAt', 'postedAt', 'date', 'createdAt', 'timestamp', 'published_at']));
  if (authorName && !group.author.name) group.author.name = authorName;
  if (authorUrl && !group.author.url) group.author.url = authorUrl;
  if (authorRole && !group.author.role) group.author.role = authorRole;
  if (!group.author.canonical_id) group.author.canonical_id = authorUrl || group.author.name || `author:${hash(groupKey)}`;
  group.rawSources.push(JSON.stringify(row).slice(0, 20000));

  const commentsValue = pick(row, ['comments', 'replies', 'postComments', 'topComments']);
  if (Array.isArray(commentsValue)) {
    commentsValue.slice(0, 20).forEach((comment, index) => addComment(group, makeComment(comment, index, groupKey)));
  }

  const rowType = String(pick(row, ['content_type', 'type', 'recordType', 'objectType']) || '').toLowerCase();
  const looksLikeComment = rowType.includes('comment') || Boolean(pick(row, ['parentId', 'parentUrn', 'parentPostId', 'parentCommentId', 'replyTo', 'inReplyTo']));
  if (looksLikeComment && text) {
    addComment(group, makeComment({ ...row, text }, group.comments.length, groupKey));
  }
}

const candidates = [...groups.values()].filter((group) => group.text || group.comments.length);
if (!candidates.length) {
  throw new Error('Apify returned no parseable LinkedIn post records for the provided URL.');
}

candidates.sort((a, b) => {
  const aMatch = testPostUrl && a.url === testPostUrl ? 1 : 0;
  const bMatch = testPostUrl && b.url === testPostUrl ? 1 : 0;
  if (bMatch !== aMatch) return bMatch - aMatch;
  if (b.comments.length !== a.comments.length) return b.comments.length - a.comments.length;
  return String(b.text || '').length - String(a.text || '').length;
});

const primary = candidates[0];
return [{
  json: {
    canonical_id: primary.canonical_id,
    content_type: primary.comments.length ? 'post_with_comments' : 'post',
    url: primary.url || testPostUrl,
    published_at: primary.published_at,
    author: primary.author,
    text: primary.text,
    comments: primary.comments,
    expected,
    raw_source: JSON.stringify(rows).slice(0, 90000),
    apify_item_count: rows.length,
    seen_at: new Date().toISOString()
  }
}];

const readOutputText = (response) => {
  if (response.output_text) return response.output_text;
  if (Array.isArray(response.output)) {
    for (const output of response.output) {
      for (const content of output.content || []) {
        if (content.type === 'output_text' && content.text) return content.text;
        if (content.text) return content.text;
      }
    }
  }
  if (response.choices && response.choices[0] && response.choices[0].message) return response.choices[0].message.content;
  return '';
};

return items.map((item) => {
  const source = item.json;
  const text = readOutputText(source);
  let score;
  try {
    score = JSON.parse(text);
  } catch (error) {
    score = {
      canonical_id: source?.canonical_id || 'parse_error',
      content_type: 'post',
      language: 'unknown',
      author_type: 'unknown',
      author_score: 0,
      post_score: 0,
      comment_score: 0,
      discussion_value: 0,
      strategic_interaction_potential: 0,
      recommended_action: 'ignore',
      relevance_tags: ['low_value'],
      low_value_flags: ['none'],
      emerging_themes: [],
      why_relevant: '',
      key_thesis: '',
      rationale: `OpenAI response parse failed: ${error.message}`,
      confidence: 0
    };
  }

  const band = (value) => {
    const n = Number(value || 0);
    if (n >= 75) return 'high';
    if (n >= 45) return 'medium';
    return 'low';
  };

  const expected = source.expected || null;
  const comparison = expected ? {
    post_score: expected.post_score || null,
    author_score: expected.author_score || null,
    discussion_value: expected.discussion_value || null,
    strategic_interaction_potential: expected.strategic_interaction_potential || null,
    matches_expected: {
      post_score: expected.post_score ? band(score.post_score) === expected.post_score : null,
      author_score: expected.author_score ? band(score.author_score) === expected.author_score : null,
      discussion_value: expected.discussion_value ? band(score.discussion_value) === expected.discussion_value : null,
      strategic_interaction_potential: expected.strategic_interaction_potential ? band(score.strategic_interaction_potential) === expected.strategic_interaction_potential : null
    }
  } : null;

  return {
    json: {
      test_input: {
        canonical_id: source.canonical_id,
        url: source.url || '',
        author: source.author || null,
        text: source.text || '',
        comments: source.comments || [],
        expected
      },
      score,
      score_bands: {
        author_score: band(score.author_score),
        post_score: band(score.post_score),
        comment_score: band(score.comment_score),
        discussion_value: band(score.discussion_value),
        strategic_interaction_potential: band(score.strategic_interaction_potential)
      },
      comparison,
      openai_response_id: source.id || ''
    }
  };
});
